import{_ as t,o as r,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"4. Definitions","description":"","frontmatter":{"title":"4. Definitions","eba":"Nurses and Midwives 2024-2028","topics":["leave","hours"]},"headers":[],"relativePath":"ebas/nurses-midwives/preliminary/4-definitions.md","filePath":"ebas/nurses-midwives/preliminary/4-definitions.md"}'),a={name:"ebas/nurses-midwives/preliminary/4-definitions.md"};function o(s,e,p,l,d,h){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_4-definitions" tabindex="-1">4. Definitions <a class="header-anchor" href="#_4-definitions" aria-label="Permalink to &quot;4. Definitions&quot;">​</a></h1><p><strong>4.1</strong> In this Agreement except where the context requires otherwise:</p><p><strong>(a)</strong> 2016 Agreement means the Nurses and Midwives (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2016-2020.</p><p><strong>(b)</strong> 2020 Agreement means the Nurses and Midwives (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2020-2024.</p><p><strong>(c)</strong> Act means the Fair Work Act 2009 (Cth).</p><p><strong>(d)</strong> ADO means an accrued day off as defined by <a href="/eba/ebas/nurses-midwives/hours-of-work/43-accrued-days-off.html">clause 43.1</a>.</p><p><strong>(e)</strong> Adoption includes the placement of a Child (as defined in <a href="/eba/ebas/nurses-midwives/leave/68-parental-leave.html">clause 68</a> (Parental Leave)) by permanent care order and includes kinship care where it is comparable to adoption, having regard for all the circumstances.</p><p><strong>(f)</strong> Allowable Period of Absence means five weeks in addition to the total period of paid annual, long service or personal leave which the Employee actually receives on termination or for which they are paid in lieu.</p><p><strong>(g)</strong> ANMF means the Australian Nursing and Midwifery Federation.</p><p><strong>(h)</strong> AMUM means an Employee who is a Registered Midwife appointed as an Associate Midwife Unit Manager and who, within the guidelines and practices established by the Midwife Unit Manager, assists in the overall clinical and administrative management of a ward or unit and deputises for the Midwife Unit Manager when required within these limits.</p><p><strong>(i)</strong> ANUM means an Employee who is a Registered Nurse appointed as an Associate Nurse Unit Manager and who, within the guidelines and practices established by the Nurse Unit Manager, assists in the overall clinical and administrative management of a ward or unit and deputises for the Nurse Unit Manager when required within these limits.</p><p><strong>(j)</strong> Bank Employee means a directly employed casual Employee who is engaged in relieving work of a casual nature.</p><p><strong>(k)</strong> Campus means a site operated by an Employer that provides day procedure surgery or multi-day inpatient services or residential aged care but excludes:</p><p><strong>(i)</strong> a site that is a Community Health Centre;</p><p><strong>(ii)</strong> a site where the only service is Aged Care beds that do not meet the definition of High Care beds under the Safe Patient Care Act;</p><p><strong>(iii)</strong> Dental Health Services Victoria;</p><p><strong>(iv)</strong> Private residences; and</p><p><strong>(v)</strong> a Campus during any period of a formal written Agreement signed by the ANMF Branch Secretary and the Employer made after 24 August 2020 and before 1 July 2021 specifying that the Campus is excluded from the operation of this clause,</p><p>provided that a satellite service co-located on a Campus controlled by another Employer is not a separate Campus for the purposes of this Agreement.</p><p>Part A - Preliminary</p><p>For reference, a list of Campuses as at the date of this Agreement is at <a href="/eba/ebas/nurses-midwives/appendices/08-campus-categories.html">Appendix 8</a>.</p><p><strong>(l)</strong> Commission means the Fair Work Commission or any successor body.</p><p><strong>(m)</strong> Deputy DON means an Employee who is a Registered Nurse appointed as the Deputy Director of Nursing and who deputises for the DON and assists in nursing administration.</p><p><strong>(n)</strong> DOH means the Victorian Department of Health or any successor department.</p><p><strong>(o)</strong> DOM means a Director of Midwifery. The Director of Midwifery is an Employee who is a Registered Midwife appointed as the senior midwifery executive officer, however styled, and who is responsible for the maternity service/division.</p><p><strong>(p)</strong> DON means the Director of Nursing. The Director of Nursing is an Employee who is a Registered Nurse appointed as the principal nursing executive officer, however styled, and who is responsible for the nursing service and any other service (including the training of nurses).</p><p><strong>(q)</strong> Early Parenting Centre (formerly known as Babies&#39; Homes) means a centre that provides help and support for families with children 0 to 3 years who have difficulties adjusting to, or establishing, feeding and other early childhood routines. Early Parenting Centres covered by this Agreement are Tweddle Child and Family Health Services, The Queen Elizabeth Centre, the O&#39;Connell Family Centre and any other Early Parenting Centre operated by an Employer during the life of this Agreement.</p><p><strong>(r)</strong> EFT means equivalent full-time Employee.</p><p><strong>(s)</strong> Employee means a Registered Nurse, Registered Midwife, Enrolled Nurse, Registered Undergraduate Student of Nursing, Registered Undergraduate Student of Midwifery or Registered Enrolled Nurse Student as described in <a href="/eba/ebas/nurses-midwives/safe-patient-care/106-undergraduate-employment-models.html">clause 106</a> or Trainee Enrolled Nurse as described in <a href="/eba/ebas/nurses-midwives/classification-staffing/94-trainee-enrolled-nurses.html">clause 94</a> employed by an Employer covered by this Agreement.</p><p><strong>(t)</strong> Employer means any of the health sector agencies listed in <a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a>.</p><p><strong>(u)</strong> Enrolled Nurse means a person registered in Division 2 Enrolled Nurses of the Register of Nurses of the Nursing and Midwifery Board of Australia established by the Health Practitioner Regulation National Law Act 2009 and includes a person:</p><p><strong>(i)</strong> registered in Division 2 Enrolled Nurses of the Register of Nurses of the Nursing and Midwifery Board of Australia established by the Health Practitioner Regulation National Law Act 2009 with a standard condition &quot;may practise only in the area of mothercraft nursing&quot;; or</p><p><strong>(ii)</strong> with an equivalent qualification and role as described in subclause 4.1(u)(i) above, including an early parenting practitioner employed in an Early Parenting Centre who is not a nurse,</p><p>but excludes a person employed solely or predominantly in the provision of Public Mental Health Services.</p><p>In this Agreement, &#39;employed solely or predominantly in the provision of Public Mental Health Services&#39;, refers to the service, department, unit or program of the Employer rather than the duties of the individual Employee.</p><p>Part A - Preliminary</p><p>Example: A Registered or Enrolled Nurse who works in an ED Hub in an Emergency Department providing treatment for people that present with mental health and alcohol and other drug issues is covered by this Agreement given the work of the relevant department as a whole.</p><p><strong>(v)</strong> EO Act means the Equal Opportunity Act 2010 (Vic).</p><p><strong>(w)</strong> Experience means paid service whether in Australia or internationally as a registered nurse, registered midwife or enrolled nurse, following registration by the professional registration body, in a Level in which the Employee is, or is about to be, employed except:</p><p><strong>(i)</strong> where an IQNM is granted registration with conditions, previous experience will not be counted whilst the conditions are in place. Experience as defined will count once there are no longer conditions in place;</p><p><strong>(ii)</strong> where an IQNM is granted registration subject to successful completion of a bridging program previous experience will not be counted;</p><p><strong>(iii)</strong> where an IQNM is required by the Australian professional registration body to undertake an outcome-based assessment (OBA) previous experience will not be counted.</p><p><strong>(x)</strong> FFPPOOA means first full pay period on or after.</p><p><strong>(y)</strong> FW Regulations means the Fair Work Regulations 2009 (Cth) as amended or replaced from time to time.</p><p><strong>(z)</strong> Hospital Certificate does not include an Employee&#39;s base qualification.</p><p><strong>(aa)</strong> HSU means the Health Services Union.</p><p><strong>(bb)</strong> HSR means a health and safety representative (including a deputy health and safety representative) elected under the OHS Act.</p><p><strong>(cc)</strong> Immediate family means:</p><p><strong>(i)</strong> a spouse (including a former spouse, a de facto partner and a former de facto partner) of the Employee. A de facto partner means a person who, although not legally married to the Employee, lives with the Employee in a relationship as a couple on a genuine domestic basis (whether the Employee and the person are of the same sex or different sexes);</p><p><strong>(ii)</strong> a child or an adult child (including an adopted child, a step child, a current foster child of the Employee or an ex nuptial child), parent, grandparent, grandchild or sibling of the Employee or of the Employee&#39;s spouse.</p><p><strong>(dd)</strong> IQNM means an Internationally Qualified Nurse or Midwife.</p><p><strong>(ee)</strong> Kin of a person is another person who is related to the first person according to Aboriginal or Torres Strait Islander kinship rules and kinship has a corresponding meaning.</p><p><strong>(ff)</strong> Level for the purposes of this clause 4 means a role in which the weekly salary in Schedule 2 for that role is at least equal to or comparable to the weekly salary</p><p>Part A - Preliminary</p><p>in Schedule 2 for the position in which the Employee is, or is about to be, employed.</p><p><strong>(gg)</strong> NES means the National Employment Standards as contained in sections 59 to 131 of the Act.</p><p><strong>(hh)</strong> MUM means an Employee who is a Registered Midwife appointed as a Midwife Unit Manager in charge of a maternity ward or unit and who is classified at the Nurse Manager grade of NM 2, 3 or 4 in accordance with <a href="/eba/ebas/nurses-midwives/classification-staffing/84-translation-arrangements-for-registered-nurses-midwives.html">clause 84.4</a>.</p><p><strong>(ii)</strong> NUM means an Employee who is a Registered Nurse appointed as a Nurse Unit Manager in charge of a ward or unit and who is classified at the Nurse Manager grade of NM 2, 3 or 4 in accordance with <a href="/eba/ebas/nurses-midwives/classification-staffing/84-translation-arrangements-for-registered-nurses-midwives.html">clause 84.4</a>.</p><p><strong>(jj)</strong> Nurse means a Registered Nurse or Enrolled Nurse.</p><p><strong>(kk)</strong> Nursing and Midwifery Board of Australia (or NMBA) includes its predecessor bodies.</p><p><strong>(ll)</strong> OHS Act means the Occupational Health and Safety Act 2004 (Vic).</p><p><strong>(mm)</strong> Public Mental Health Services means mental health services delivered on a service, department, unit or program level and operated by an employer covered by the Victorian Public Mental Health Services Enterprise Agreement 2016-2020 (or its successor).</p><p><strong>(nn)</strong> Pool Employee means a class of non-casual Employees who agree to be available for deployment across all or part of a Health Service.</p><p><strong>(oo)</strong> Registered Health Practitioner means an individual who is registered under the Health Practitioner Regulation National Law (as in force in the applicable State or Territory) to practise a health profession, other than as a student.</p><p><strong>(pp)</strong> Registered Nurse means a person registered in Division 1 Registered Nurses of the Register of Nurses of the Nursing and Midwifery Board of Australia established by the Health Practitioners Regulation National Law Act 2009 but excludes a person employed solely or predominantly in the provision of Public Mental Health Services.</p><p>In this Agreement, &#39;employed solely or predominantly in the provision of Public Mental Health Services&#39;, refers to the service, department, unit or program of the Employer rather than the duties of the individual Employee.</p><p>Example: A Registered or Enrolled Nurse who works in an ED Hub in an Emergency Department providing treatment for people that present with mental health and alcohol and other drug issues is covered by this Agreement given the work of the relevant department as a whole.</p><p><strong>(qq)</strong> Registered Midwife or Midwife means a person registered as a Midwife on the Register of Midwives of the Nursing and Midwifery Board of Australia established under the Health Practitioners Regulation National Law Act 2009.</p><p><strong>(rr)</strong> Safe Patient Care Act means the Safe Patient Care (Nurse to Patient and Midwife to Patient Ratios) Act 2015 (Vic).</p><p><strong>(ss)</strong> Short Shift means a shift of six hours duration in addition to a 30-minute meal break.</p><p>Part A - Preliminary</p><p><strong>(tt)</strong> 24 hours a day, seven days per week areas means wards/units/divisions of a hospital Campus/facility that have a staffing roster that operates over 24 hours a day for seven days a week.</p><p><strong>(uu)</strong> Union means ANMF for all Employees or HSU (with respect to Enrolled Nurses only). When used in the plural, Unions means the ANMF and the HSU (with respect to Enrolled Nurses only).</p><p><strong>(vv)</strong> VHIA means the Victorian Hospitals&#39; Industrial Association.</p><p><strong>(ww)</strong> WIC means the Workplace Implementation Committee referenced at clause 80.10.</p><p><strong>(xx)</strong> WIRC Act means the Workplace Injury Rehabilitation and Compensation Act 2013 (Vic), or if applicable in the particular situation the Accident Compensation Act 1985 (Vic) or the Workers Compensation Act 1958 (Vic).</p><p><strong>(yy)</strong> a Year of Experience in this Agreement means:</p><p><strong>(i)</strong> an average of three shifts or more per week in a year. If the Employee averages less than three shifts per week or 48 hours per fortnight (whichever is the lesser), the Employee will need to complete an additional year to advance;</p><p><strong>(ii)</strong> in the case of an IQNM registering in Australia for the first time who was not required by the Australian professional registration body to undertake either a bridging program or outcome-based assessment (OBA), a Year of Experience means:</p><p><strong>(A)</strong> an average of at least 48 hours per fortnight; and</p><p><strong>(B)</strong> for each year in which the IQNM averages less than 48 hours per fortnight, the Employee will need to complete an additional year to advance.</p><p><strong>(iii)</strong> For the purpose of being classified under this Agreement, upon commencement with an Employer:</p><p><strong>(A)</strong> subject to (iv) below, an Employee&#39;s anniversary date is the date the Employee commenced work as a Registered Nurse (where that Employee was not already a Registered Midwife), Registered Midwife (where that Employee was not already a Registered Nurse) or Enrolled Nurse following registration either in Australia or internationally; or</p><p><strong>(B)</strong> in the case of an IQNM required to undertake a bridging program or OBA in order to be registered in Australia, the date the Employee commenced work as a Registered Nurse, Registered Midwife or Enrolled Nurse following registration in Australia.</p><p><strong>(iv)</strong> For the purpose of experience advancement under this Agreement, upon commencement with an Employer:</p><p><strong>(A)</strong> an Employee&#39;s anniversary date is the date the Employee commenced work as a Registered Nurse (where that Employee was not already a Registered Midwife), Registered Midwife (where that Employee was not already a Registered Nurse) or Enrolled Nurse following</p><p>Part A - Preliminary</p><p>registration either in Australia or internationally (subject to 4.1(yy)(i));</p><p><strong>(B)</strong> Years of Experience are relevant to determining the appropriate increment within a grade, Years of Experience are calculated from the Employee&#39;s anniversary date; and</p><p><strong>(C)</strong> the onus is on the Employee to demonstrate the completed Years of Experience and anniversary date. The Employer may require evidence that would satisfy a reasonable person of the claimed experience with the previous Employer/s.</p><p><strong>(v)</strong> Experience can be with concurrent Employer/s, on provision by the Employee of evidence of experience with other Employer/s save that:</p><p><strong>(A)</strong> Any new increment is payable from the FFPPOOA, the evidence is provided; and</p><p><strong>(B)</strong> Notwithstanding this term, any previously recognised concurrent service is unaffected by this term.</p><p><strong>(vi)</strong> Note: Experience and Years of Experience are only relevant to determining what constitutes experience (including previous experience) for the purpose of incremental progression through an Employee&#39;s classification.</p><p><strong>4.2</strong> Relevant qualification/relevant component of a qualification etc.</p><p>Where a provision of this Agreement requires consideration of the relevance of a qualification or certificate (including components of a qualification or certificate) or course of study or similar (education):</p><p><strong>(a)</strong> the main criteria for considering relevance are:</p><p><strong>(i)</strong> the nature of the education; and</p><p><strong>(ii)</strong> the current area of practice of the Employee; and</p><p><strong>(b)</strong> other considerations may include:</p><p><strong>(i)</strong> the clinical or other area of work of the Employee;</p><p><strong>(ii)</strong> the classification and position description of the Employee; and/or</p><p><strong>(iii)</strong> whether the education would assist the Employee in performing their role and/or assist in maintaining quality patient care and/or assist in the administration of the ward/unit/area in which the Employee is employed.</p><p><strong>4.3</strong> For the purpose of the NES, a shiftworker is defined as an Employee who:</p><p><strong>(a)</strong> is regularly rostered over seven days of the week; and</p><p><strong>(b)</strong> regularly works on weekends.</p><p>Part A - Preliminary</p><p><strong>4.4</strong> Where any legislation other than the Safe Patient Care Act referred to in this Agreement is or has been replaced by successor legislation, the reference to such legislation will be taken to refer to the successor legislation.</p><p><strong>4.5</strong> Where this Agreement refers to a condition of employment provided for in the NES, the relevant definitions in the Act apply unless otherwise defined in this Agreement.</p><p><strong>4.6</strong> All Employees will be classified in accordance with the Agreement, but where there is no apparent classification for an Employee or for an Employee performing particular work, the appropriate classification will be determined by the Panel in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.html">clause 14</a>.</p><p>Plain language terms: dictionary, glossary, meanings.</p>',111)])])}const m=t(a,[["render",o]]);export{c as __pageData,m as default};
